var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"8년 후, 측정불가 심도. 차원함선 마타도르.","JPN":"8年後、測定不可の深度。次元艦船\\tマタドール","ENG":"Eight years later, Dive Depth Unknown. Dimensional ship Matador.","TWN":"8年後，無法測量的深度，次元艦船 鬥牛士","SCN":"8年后，无法测量的深度。次元舰船斗牛士。","DEU":"Eight years later, Dive Depth Unknown. Dimensional ship Matador.","FRA":"Eight years later, Dive Depth Unknown. Dimensional ship Matador."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"좌표 연산 완료.","JPN":"座標演算完了。","ENG":"Coordinates calculation complete.","TWN":"座標運算完成。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"허수 잠항 모듈 체크.","JPN":"虚数潜航モジュールチェック。","ENG":"Imaginary dive module check.","TWN":"檢查虛數潛航模組。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이터니움 드라이브 점화.","JPN":"エタニウムドライブ点火。","ENG":"Igniting Eternium Drive.","TWN":"永恆之金驅動器啟動。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"목적지는 허수공간의 한복판의 특정 좌표, A.K.A 호랑이굴.","JPN":"目的地は虚数空間中央の特定座標、A.K.A、虎穴。","ENG":"Destination set to the coordinates deep in the imaginary space, A.K.A. the Tiger's Den.","TWN":"目的地是虛數空間的正中央的特定座標，A.K.A.虎血。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"차원 돌파 개시.","JPN":"次元突破開始。","ENG":"Initiating dimensional breach.","TWN":"次元突破開始。"},"stage":{"bg":"VOID","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"이로서 우리의 여정은 마지막 단계에 이르렀도다.","JPN":"これで俺らの旅は最終段階を迎えた。","ENG":"At last, our journey reaches its final step.","TWN":"至此，我們的旅程來到了最後階段。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"만약 좌표 설정이 잘못 됐다면, 우린 이대로 영원히 허수공간을 떠돌게 될 거야.","JPN":"もし座標設定が間違ってたら、俺らはこのまま永遠に虚数空間で漂流者になっちまう。","ENG":"If the coordinates are even a little off, we're gonna be drifting through the imaginary space forever.","TWN":"如果座標設定錯誤，我們就會永遠在虛數空間中漂流。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아니면 차원압에 의해 죽음의 공포를 느낄 새도 없이 쥐포가 되거나?","JPN":"それか、死の恐怖を感じる暇もなく次元圧でペチャンコになったり？","ENG":"Or worse, we get crushed by dimensional pressure and turned into jerky before we even realize we're dead.","TWN":"或者被次元壓力壓成肉醬，連感到死亡的恐懼都來不及？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"좌표는 걱정 마. <color=#ffd34c>우물</color>에서 발견한 동앗줄에 기록된 연산좌표값을 그대로 이식해온 거니까.","JPN":"座標のことは心配するな。<color=#ffd34c>井戸</color>で見つかった縄に記録されてる演算座標値をそのまま移植したから。","ENG":"Relax. I ported the exact numbers from the Tether we found in the <color=#ffd34c>Well</color>.","TWN":"座標不用擔心。我是直接移植了在<color=#ffd34c>井</color>裡發現的繩索上紀錄的運算座標值。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"그래서 더 믿음이 안 간다고. 그건 누가 봐도 썩기 직전의 밧줄이었잖아!","JPN":"だから余計に信用できねえんだよ。あの縄、どう見ても腐る寸前だっただろう！","ENG":"Yeah, and that's exactly why I don't trust it. That thing looked like it was one tug away from disintegrating.","TWN":"這才更讓人不信任。那怎麼看都像是腐爛前的繩子啊！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>동앗줄</color>이 생긴 건 좀 그래 보여도 관리국의 것들 못지 않게 정교한 기술력의 집약체였어.","JPN":"<color=#ffd34c>縄</color>は見た目はああだが、管理局に引けを取らない精巧な技術力が詰まっていた。","ENG":"It may have looked nasty, but that <color=#ffd34c>Tether</color> was packed with tech just as sophisticated as anything the Administration made.","TWN":"<color=#ffd34c>繩索</color>雖然看起來不怎麼樣，但卻是集結了不亞於管理局的精巧技術。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 나유빈이란 작자가 설명한 대로라면 차원함선으론 간섭이 불가능한 시간축까지 고정하는 장치인 셈이니까. 한 번 믿어보라고.","JPN":"あのイチノセ・カオルってやつの説明通りなら、次元艦船だけでは干渉できない時間軸まで固定できる装置ってことだ。1度だけ信じてみよう。","ENG":"If what Na Yubin said is true, it's a device that locks down even time axes dimensional ships can't touch. Try having a little faith.","TWN":"如果按照那個叫羅有彬的傢伙所說，這東西甚至可以固定次元艦船無法干涉的時間軸。相信我一次。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"실패하면 두 번째는 어디 있는데? 내가 그 정도 산수도 못하는 줄 알아?","JPN":"失敗したら2度目はあるのか？　俺にそれぐらいの計算もできねえと思ってるのか！？","ENG":"And if we screw this up, where's the second chance, huh? I can do basic math, you know.","TWN":"如果失敗了，還有第二次機會嗎？你以為我算不出來嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"시끄러워.","JPN":"うるさい。","ENG":"Shut up.","TWN":"吵死了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"떠들 시간 있으면 도착하기 전에 저 녀석처럼 잠이나 자두라고.","JPN":"騒ぐ暇があるなら、到着するまであいつみたいに睡眠でもとっておけ。","ENG":"If you've got time to flap your gums, maybe take a nap like that one over there.","TWN":"有時間說話，不如在抵達前像那傢伙一樣睡一覺。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"절 말씀하시는 거라면, 아까부터 멀쩡히 깨어있습니다만.","JPN":"僕のことでしたら、さっきから普通に起きてましたけど。","ENG":"If you meant me, I've been perfectly awake for a while now.","TWN":"如果你說的是我，那我從剛才就一直醒著。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"…헷갈린단 말이다. 그 눈.","JPN":"……分かりずらいんだよ、その目。","ENG":"…Your eyes. They're confusing.","TWN":"…真讓人困惑。那雙眼睛。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아하하, 역시 극악무도한 해적답게 남이 상처 받을 말씀을 아무렇지 않게 하시네요.","JPN":"ハハ、さすが極悪非道な海賊らしく、人が傷つくようなことをさらっと言いますね。","ENG":"Ahaha, leave it to a merciless pirate to toss out such casual insults.","TWN":"哈哈哈，果然是極其兇惡的海盜，毫不猶豫地說出傷害人的話。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"눈 붙일 생각 없으면, 다음 계획이나 다시 읊어보는 게 어때.","JPN":"寝る気がないなら、次の計画をもう一度説明したらどうだ。","ENG":"If you're not sleeping, why don't you walk us through the next plan again.","TWN":"如果不打算睡覺，不如再複習一下下一個計畫。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"깡통, 어려울 게 뭐 있다고 자꾸 물어봐?","JPN":"ボロ缶、別に難しいことねえだろ？","ENG":"Tin Can, why do you keep asking? It's not hard.","TWN":"蠢蛋，有什麼好一直問的？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"계획은 우리 신참… 아니, 임시 대장이 괴물을 혼내줄 동안 <color=#ffd34c>보물</color>을 찾아서 튄다. 틀려?","JPN":"うちの新入り……じゃなくて、臨時隊長が化け物をやっつける間に俺らは<color=#ffd34c>宝</color>を探して逃げるってのが計画だろ、な？","ENG":"The plan is, while our rookie– I mean, our temp captain, picks a fight with the monster, we swipe the <color=#ffd34c>treasure</color> and make a break for it. Sound about right?","TWN":"計畫就是我們的新手…不，是臨時隊長去教訓怪物，我們去尋找<color=#ffd34c>寶物</color>然後開溜。說錯了嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"정확하네요.","JPN":"その通りです。","ENG":"That's exactly right.","TWN":"很準確。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"조금 덧붙이자면, 그 괴물이 저흴 순식간에 없앨 수 있을 만큼 위험하다는 정도?","JPN":"少しつけ足しますと、その化け物は僕たちを一瞬で消せるほど危ないということぐらいですかね。","ENG":"Though I'd add, the monster's dangerous enough to wipe us out before we blink.","TWN":"如果再補充一點，就是那個怪物危險到可以在瞬間消滅我們？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"ROJO_SCAVENGER_NULL_NULL","text":{"KOREA":"관리국 놈들이 신형 모듈을 무일푼으로 넘겨줄 때부터 그런 건 예상했다. 어차피 싸움은 네 몫이 될 테고, 우린 버림패로 쓰일 승무원과 함선만 제공하면 되는 거니까.","JPN":"そんなことは、管理局のやつらが新型モジュールを無料で渡した時から予想していた。どうせ戦闘はお前の担当になるだろうし、俺たちはお望みどおり捨て駒になる乗務員や艦船を提供するだけだ。","ENG":"We figured that out the second the Administration handed us top-shelf tech for free. They expect you to do the fighting while we haul the disposable crew and ship around.","TWN":"管理局那幫傢伙無償提供新型模組時，我就預料到了。反正戰鬥是你的事，我們只要提供當作棄子使用的船員和艦船就行。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ROJO_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_PRIDE"}}}}]`);export{e as default};